const IOSAlert={alert:(t,e,n="确定")=>new Promise((s=>{const o=document.getElementById("iosAlert"),l=document.getElementById("iosAlertTitle"),c=document.getElementById("iosAlertMessage"),i=document.getElementById("iosAlertActions");l.textContent=t,c.textContent=e,c.style.display=e?"block":"none",i.innerHTML=`\n                <button class="ios-alert-btn primary">${n}</button>\n            `,o.classList.add("active");i.querySelector("button").addEventListener("click",(()=>{o.classList.remove("active"),s(!0)}))})),confirm:(t,e,n="确定",s="取消")=>new Promise((o=>{const l=document.getElementById("iosAlert"),c=document.getElementById("iosAlertTitle"),i=document.getElementById("iosAlertMessage"),r=document.getElementById("iosAlertActions");c.textContent=t,i.textContent=e,i.style.display=e?"block":"none",r.innerHTML=`\n                <button class="ios-alert-btn cancel">${s}</button>\n                <button class="ios-alert-btn primary">${n}</button>\n            `,l.classList.add("active");const a=r.querySelectorAll("button");a[0].addEventListener("click",(()=>{l.classList.remove("active"),o(!1)})),a[1].addEventListener("click",(()=>{l.classList.remove("active"),o(!0)}))})),confirmDestructive:(t,e,n="删除",s="取消")=>new Promise((o=>{const l=document.getElementById("iosAlert"),c=document.getElementById("iosAlertTitle"),i=document.getElementById("iosAlertMessage"),r=document.getElementById("iosAlertActions");c.textContent=t,i.textContent=e,i.style.display=e?"block":"none",r.innerHTML=`\n                <button class="ios-alert-btn cancel">${s}</button>\n                <button class="ios-alert-btn destructive">${n}</button>\n            `,l.classList.add("active");const a=r.querySelectorAll("button");a[0].addEventListener("click",(()=>{l.classList.remove("active"),o(!1)})),a[1].addEventListener("click",(()=>{l.classList.remove("active"),o(!0)}))}))};